import { useEffect, useCallback } from 'react';
import { bus, type AppEventMap } from './eventBus';

/**
 * Subscribe to an event bus event. Automatically cleans up on unmount.
 */
export function useEventBus<K extends keyof AppEventMap>(
  event: K,
  handler: (data: AppEventMap[K]) => void
): void {
  useEffect(() => {
    const unsubscribe = bus.on(event, handler);
    return unsubscribe; // Cleanup on unmount
  }, [event, handler]);
}

/**
 * Get a stable emit function for an event.
 */
export function useEmit<K extends keyof AppEventMap>(event: K) {
  return useCallback(
    (...args: AppEventMap[K] extends undefined ? [] : [AppEventMap[K]]) => {
      bus.emit(event, ...args);
    },
    [event]
  );
}

