import logging

logger = logging.getLogger(__name__)


class EventDispatcher:
    """Simple synchronous event dispatcher."""

    def __init__(self) -> None:
        self._handlers: dict[str, list[Callable]] = defaultdict(list)

    def on(self, event: str, handler: Callable) -> Callable:
        """Register a handler for an event. Returns the handler for chaining."""
        self._handlers[event].append(handler)
        return handler

    def off(self, event: str, handler: Callable) -> None:
        """Remove a handler from an event."""
        self._handlers[event].remove(handler)

    def emit(self, event: str, **data: Any) -> list[Any]:
        """Emit an event. All registered handlers are called synchronously."""
        results = []
        for handler in self._handlers.get(event, []):
            try:
                result = handler(**data)
                results.append(result)
            except Exception as e:
                logger.error(f"Error in handler for '{event}': {e}", exc_info=True)
        return results

    def handler_count(self, event: str) -> int:
        return len(self._handlers.get(event, []))


