# Each connected client gets a queue
clients: list[queue.Queue] = []


def format_sse(data: dict, event: str | None = None, retry: int | None = None) -> str:
    """Format data as an SSE message."""
    lines = []
    if event:
        lines.append(f"event: {event}")
    if retry:
        lines.append(f"retry: {retry}")
    lines.append(f"data: {json.dumps(data)}")
    return "\n".join(lines) + "\n\n"


def event_stream(client_queue: queue.Queue):
    """Generator that yields SSE messages from the client's queue."""
    try:
        while True:
            # Block until a message is available (timeout prevents zombie connections)
            try:
                message = client_queue.get(timeout=30)
                yield message
            except queue.Empty:
                # Send a keep-alive comment to prevent connection timeout
                yield ": heartbeat\n\n"
    finally:
        # Clean up when client disconnects
        clients.remove(client_queue)


@app.get("/api/events")
def sse_endpoint():
    """SSE endpoint -- clients connect here to receive real-time events."""
    client_queue: queue.Queue = queue.Queue()
    clients.append(client_queue)

    # Send initial connection event
    client_queue.put(format_sse(
        {"message": "Connected to event stream"},
        event="connected",
        retry=5000,  # Client retries in 5 seconds if disconnected
    ))

    return Response(
        event_stream(client_queue),
        mimetype="text/event-stream",
        headers={
            "Cache-Control": "no-cache",
            "X-Accel-Buffering": "no",  # Disable Nginx buffering
        },
    )


def broadcast(data: dict, event: str | None = None):
    """Send an event to all connected clients."""
    message = format_sse(data, event=event)
    for client_queue in clients:
        client_queue.put(message)


